import { useLayoutEffect, useState } from "react";
import { getConsumedSparePartsData } from "../../../../api";
import { useSetRecoilState } from "recoil";
import { Notification } from "../../../../modules/global/global-states";

type ConsumedSparePart = {
  brand: string;
  code: string;
  description: string;
  id: number;
  model: string;
  partsDescr: string;
  period: string;
  quantity: number;
};

export function useConsumedSparePartsTableHooks() {
  const setNotification = useSetRecoilState(Notification);
  const [consumedSparePartsData, setConsumedSparePartsData] = useState<
    ConsumedSparePart[]
  >([]);
  useLayoutEffect(() => {
    getConsumedSparePartsData()
      .then((res) => {
        setConsumedSparePartsData(res);
        console.log(res);
      })
      .catch((err) => {
        setNotification({
          title: "Error fetching the top 5 consumed spare parts",
          message: JSON.stringify(err),
          level: 2,
        });
      });
  }, [setNotification]);
  return consumedSparePartsData;
}
